    reasonCode: GRAPH_RUNTIME_CONSUMER_DISABLED_REASON_CODE,
    requiredGuards: {
      integrationCheckpoint:
        'assertGraphDocsOutputLiveLayerConsumerIntegrationCheckpointCompatibility',
      dispatchDryRunResult:
        'assertGraphDocsOutputLiveConsumerDispatchDryRunResultCompatibility',
      docsMarkdownConsumer: 'assertGraphDocsMarkdownArtifactConsumerCompatibility',
    },
    sourceIntegrationCheckpoint:
      createGraphDocsOutputLiveConsumerDispatchDryRunCheckpointSummary(checkpoint),
    sourceArtifact:
      createGraphDocsOutputLiveConsumerDispatchDryRunArtifactSummary(dispatchArtifact),
    consumerResultCount: consumerResultSummaries.length,
