function collectProvidedGraphDocsOutputLiveConsumerSourceAliases(
  options,
  aliasNames,
  label,
  assertNoRuntimeProducts,
) {
  const providedAliases = aliasNames
    .filter((aliasName) => (
      Object.hasOwn(options, aliasName)
        && options[aliasName] !== undefined
    ))
    .map((aliasName) => ({
      aliasName,
      value: options[aliasName],
    }));
  for (const { aliasName, value } of providedAliases) {
    assertNoRuntimeProducts(value, label, `${label}.${aliasName}`);
  }
  if (providedAliases.length <= 1) {
    return providedAliases[0]?.value;
  }
  const [{ value: firstValue }] = providedAliases;
  const distinctAlias = providedAliases
    .find(({ value }) => value !== firstValue);
  if (distinctAlias) {
    throw new Error(`${label} source aliases must reference the same descriptor object`);
  }
  return firstValue;
}

