function assertTempDirPlacement(placement = {}, label) {
  assertPlainObject(placement, label);
  if (placement.schemaVersion !== GRAPH_DERIVED_ARTIFACT_PLACEMENT_SCHEMA_VERSION) {
    throw new Error(`${label} schemaVersion is not compatible`);
  }
  if (placement.placementKind !== 'site-capability-graph-derived-artifact-pair') {
    throw new Error(`${label} placementKind is not supported`);
  }
  if (placement.redactionRequired !== true) {
    throw new Error(`${label} redactionRequired must be true`);
  }
  if (placement.artifactFamily !== 'site-capability-graph-docs-markdown') {
    throw new Error(`${label} artifactFamily must be site-capability-graph-docs-markdown`);
  }
  const outputDir = path.resolve(assertPathText(placement.outputDir, `${label}.outputDir`));
  const tempDir = path.resolve(os.tmpdir());
  const relativeToTemp = path.relative(tempDir, outputDir);
  if (relativeToTemp.startsWith('..') || path.isAbsolute(relativeToTemp)) {
    throw new Error(`${label} outputDir must stay under the system temp directory`);
  }
  const artifactTarget = resolveOutputPath(
    outputDir,
    placement.artifactFileName,
    `${label}.artifactFileName`,
  );
  const auditTarget = resolveOutputPath(
    outputDir,
    placement.auditFileName,
    `${label}.auditFileName`,
  );
  if (path.resolve(placement.artifactPath) !== artifactTarget.resolved) {
    throw new Error(`${label} artifactPath must match artifactFileName inside outputDir`);
  }
  if (path.resolve(placement.auditPath) !== auditTarget.resolved) {
    throw new Error(`${label} auditPath must match auditFileName inside outputDir`);
  }
  assertNoForbiddenPatterns(placement);
  return {
    artifactFileName: placement.artifactFileName,
    auditFileName: placement.auditFileName,
  };
}

