export function assertGraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidenceCompatibility(
  evidence = {},
) {
  assertPlainObject(
    evidence,
    'GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence',
  );
  assertNoGraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidenceRuntimeProducts(
    evidence,
    'GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence',
  );
  if (
    evidence.schemaVersion
      !== GRAPH_DOCS_OUTPUT_LIVE_CONSUMER_RUNTIME_DOCS_ARTIFACT_WRITE_OBSERVABILITY_EVIDENCE_SCHEMA_VERSION
  ) {
    throw new Error('GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence schemaVersion is not compatible');
  }
  if (
    evidence.queryName
      !== 'createGraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence'
  ) {
    throw new Error('GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence queryName is not supported');
  }
  if (
    evidence.evidenceKind
      !== 'site-capability-graph-docs-output-live-consumer-runtime-docs-artifact-write-observability-evidence'
  ) {
    throw new Error('GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence evidenceKind is not supported');
  }
  if (
    evidence.artifactFamily
      !== 'site-capability-graph-docs-output-live-consumer-runtime-docs-artifact-write-observability-evidence'
  ) {
    throw new Error('GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence artifactFamily is not supported');
  }
  if (
    evidence.redactionRequired !== true
      || evidence.safeSummaryOnly !== true
      || evidence.observabilityEvidenceOnly !== true
  ) {
    throw new Error('GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence must be observability-only safe summary evidence');
  }
  if (!['blocked', 'observed'].includes(evidence.result)) {
    throw new Error('GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence result is not supported');
  }
  for (
    const fieldName
    of GRAPH_DOCS_OUTPUT_LIVE_CONSUMER_RUNTIME_DOCS_ARTIFACT_WRITE_OBSERVABILITY_EVIDENCE_FALSE_FLAG_KEYS
  ) {
    if (evidence[fieldName] !== false) {
      throw new Error(`GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence ${fieldName} must be false`);
    }
  }
  for (const [fieldName, expected] of Object.entries({
    telemetryConnection: false,
    writerInvokedByThisApi: false,
    artifactFilesRead: false,
    auditFilesRead: false,
    runtimeDispatchPerformed: false,
    runtimeDocsWritePerformed: false,
    runtimeArtifactWritePerformed: false,
    runtimeLogWritePerformed: false,
    repoWritePerformed: false,
    docsOutputWritePerformed: false,
    registryWritePerformed: false,
    catalogWritePerformed: false,
    publishPerformed: false,
    siteAdapterInvoked: false,
    downloaderInvoked: false,
    sessionViewMaterialized: false,
    taskRunnerInvoked: false,
    statusPromotionPerformed: false,
    verifiedPromotionPerformed: false,
    graphExecutesSiteTasks: false,
    dynamicRunStatePersisted: false,
    rawSensitiveCredentialPersisted: false,
    rawSensitiveMaterialPersisted: false,
    absolutePathsOmitted: true,
  })) {
    if (evidence[fieldName] !== expected) {
      throw new Error(`GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence ${fieldName} must be ${expected}`);
    }
  }
  assertPlainObject(
    evidence.requiredGuards,
    'GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence requiredGuards',
  );
  if (
    evidence.requiredGuards.artifactWriterInvocationEvidence
      !== 'assertGraphDocsOutputLiveConsumerArtifactWriterInvocationEvidenceCompatibility'
      || evidence.requiredGuards.runtimeDocsArtifactWriteObservabilityEvidence
        !== 'assertGraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidenceCompatibility'
  ) {
    throw new Error('GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence requiredGuards are incomplete');
  }
  assertPlainObject(
    evidence.sourceArtifactWriterInvocationEvidence,
    'GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence sourceArtifactWriterInvocationEvidence',
  );
  if (
    evidence.sourceArtifactWriterInvocationEvidence.queryName
      !== 'createGraphDocsOutputLiveConsumerArtifactWriterInvocationEvidence'
  ) {
    throw new Error('GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence sourceArtifactWriterInvocationEvidence queryName is not supported');
  }
  if (evidence.reasonCode !== evidence.sourceArtifactWriterInvocationEvidence.reasonCode) {
    throw new Error('GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence reasonCode must match source evidence');
  }
  if (evidence.sourceArtifactWriterInvocationEvidence.result === 'invoked') {
    if (evidence.result !== 'observed') {
      throw new Error('GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence invoked source must be observed');
    }
    if (
      evidence.sourceArtifactWriterInvocationEvidence.auditBeforeArtifact !== true
        || evidence.sourceArtifactWriterInvocationEvidence.testHarnessOnly !== true
        || evidence.sourceArtifactWriterInvocationEvidence.outputDirKind !== 'system-temp-dir'
    ) {
      throw new Error('GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence invoked source must be temp test-harness evidence');
    }
    assertNonNegativeInteger(
      evidence.sourceArtifactWriterInvocationEvidence.auditFindingsCount,
      'GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence source auditFindingsCount',
    );
    assertNonNegativeInteger(
      evidence.sourceArtifactWriterInvocationEvidence.auditRedactionsCount,
      'GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence source auditRedactionsCount',
    );
    if (evidence.sourceArtifactWriterInvocationEvidence.redactionAuditAttachment !== undefined) {
      assertRedactionAuditAttachmentSummaryCompatible(
        evidence.sourceArtifactWriterInvocationEvidence.redactionAuditAttachment,
        'GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence source redactionAuditAttachment',
      );
    }
  } else if (evidence.result !== 'blocked') {
    throw new Error('GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence blocked source must stay blocked');
  }
  return true;
}

export function createGraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence(
  optionsOrArtifactWriterInvocationEvidence = {},
  positionalOptions,
) {
  const isDirectArtifactWriterInvocationEvidence = positionalOptions === undefined
    && optionsOrArtifactWriterInvocationEvidence?.queryName
      === 'createGraphDocsOutputLiveConsumerArtifactWriterInvocationEvidence';
  const options = positionalOptions === undefined
    ? (
      isDirectArtifactWriterInvocationEvidence
        ? {
          artifactWriterInvocationEvidence:
            optionsOrArtifactWriterInvocationEvidence,
          sourceArtifactWriterInvocationEvidence:
            optionsOrArtifactWriterInvocationEvidence,
        }
        : optionsOrArtifactWriterInvocationEvidence
    )
    : {
      artifactWriterInvocationEvidence:
        optionsOrArtifactWriterInvocationEvidence,
      ...positionalOptions,
    };
  assertPlainObject(
    options,
    'GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidenceOptions',
  );
  const {
    artifactWriterInvocationEvidence,
    sourceArtifactWriterInvocationEvidence,
    sourceEvidence,
    evidence,
    graphVersion = artifactWriterInvocationEvidence?.graphVersion
      ?? sourceArtifactWriterInvocationEvidence?.graphVersion
      ?? sourceEvidence?.graphVersion
      ?? evidence?.graphVersion
      ?? 'graph-docs-output-live-consumer-runtime-docs-artifact-write-observability-evidence-v1',
    ...evidenceOptions
  } = options;
  assertNoGraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidenceRuntimeProducts(
    evidenceOptions,
    'GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidenceOptions',
  );
  const sourceAliasEntries = [
    ['artifactWriterInvocationEvidence', artifactWriterInvocationEvidence],
    ['sourceArtifactWriterInvocationEvidence', sourceArtifactWriterInvocationEvidence],
    ['sourceEvidence', sourceEvidence],
    ['evidence', evidence],
  ].filter(([, sourceAlias]) => sourceAlias !== undefined);
  for (const [aliasName, sourceAlias] of sourceAliasEntries) {
    assertNoGraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidenceRuntimeProducts(
      sourceAlias,
      `GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidenceOptions ${aliasName}`,
    );
  }
  const firstSourceAlias = sourceAliasEntries[0]?.[1];
  for (const [aliasName, sourceAlias] of sourceAliasEntries.slice(1)) {
    if (sourceAlias !== firstSourceAlias) {
      throw new Error(
        'GraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidenceOptions '
          + `must not provide multiple distinct source aliases: ${aliasName}`,
      );
    }
  }
  const source = artifactWriterInvocationEvidence
    ?? sourceArtifactWriterInvocationEvidence
    ?? sourceEvidence
    ?? evidence;
  const sourceArtifactWriterInvocationEvidenceSummary =
    createGraphDocsOutputLiveConsumerArtifactWriterInvocationEvidenceSafeSummary(
      source,
    );
  const disabledFlags = Object.fromEntries(
    GRAPH_DOCS_OUTPUT_LIVE_CONSUMER_RUNTIME_DOCS_ARTIFACT_WRITE_OBSERVABILITY_EVIDENCE_FALSE_FLAG_KEYS
      .map((fieldName) => [fieldName, false]),
  );
  const observabilityEvidence = {
    schemaVersion:
      GRAPH_DOCS_OUTPUT_LIVE_CONSUMER_RUNTIME_DOCS_ARTIFACT_WRITE_OBSERVABILITY_EVIDENCE_SCHEMA_VERSION,
    queryName:
      'createGraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidence',
    evidenceKind:
      'site-capability-graph-docs-output-live-consumer-runtime-docs-artifact-write-observability-evidence',
    artifactFamily:
      'site-capability-graph-docs-output-live-consumer-runtime-docs-artifact-write-observability-evidence',
    graphVersion,
    redactionRequired: true,
    safeSummaryOnly: true,
    observabilityEvidenceOnly: true,
    result: sourceArtifactWriterInvocationEvidenceSummary.result === 'invoked'
      ? 'observed'
      : 'blocked',
    reasonCode: sourceArtifactWriterInvocationEvidenceSummary.reasonCode,
    telemetryConnection: false,
    writerInvokedByThisApi: false,
    artifactFilesRead: false,
    auditFilesRead: false,
    runtimeDispatchPerformed: false,
    runtimeDocsWritePerformed: false,
    runtimeArtifactWritePerformed: false,
    runtimeLogWritePerformed: false,
    repoWritePerformed: false,
    docsOutputWritePerformed: false,
    registryWritePerformed: false,
    catalogWritePerformed: false,
    publishPerformed: false,
    siteAdapterInvoked: false,
    downloaderInvoked: false,
    sessionViewMaterialized: false,
    taskRunnerInvoked: false,
    statusPromotionPerformed: false,
    verifiedPromotionPerformed: false,
    graphExecutesSiteTasks: false,
    dynamicRunStatePersisted: false,
    rawSensitiveCredentialPersisted: false,
    rawSensitiveMaterialPersisted: false,
    absolutePathsOmitted: true,
    requiredGuards: {
      artifactWriterInvocationEvidence:
        'assertGraphDocsOutputLiveConsumerArtifactWriterInvocationEvidenceCompatibility',
      runtimeDocsArtifactWriteObservabilityEvidence:
        'assertGraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidenceCompatibility',
    },
    sourceArtifactWriterInvocationEvidence:
      sourceArtifactWriterInvocationEvidenceSummary,
    ...disabledFlags,
  };
  assertGraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidenceCompatibility(
    observabilityEvidence,
  );
  return observabilityEvidence;
}

