function assertNoGraphDocsOutputLiveConsumerDownstreamSafeSummaryConsumerNoopRegistrationReviewScanRuntimeProducts(
  value = {},
  label = 'GraphDocsOutputLiveConsumerDownstreamSafeSummaryConsumerNoopRegistrationReviewScan',
  pathLabel = label,
) {
  assertNoGraphDocsOutputLiveConsumerDownstreamSafeSummaryConsumerEligibilityScanRuntimeProducts(
    value,
    label,
    pathLabel,
  );
  assertNoForbiddenPatterns(value);
  if (
    typeof value === 'string'
      && /(?:sk-[a-z0-9_-]{12,}|bearer\s+[a-z0-9._-]{8,}|cookie\s*=|sessdata|csrf)/iu
        .test(value)
  ) {
    throw new Error(`${label} rejected synthetic sensitive material: ${pathLabel}`);
  }
  if (!value || typeof value !== 'object') {
    if (typeof value === 'string' && path.isAbsolute(value)) {
      throw new Error(`${label} rejected absolute path string: ${pathLabel}`);
    }
    return true;
  }
  for (
    const fieldName
    of GRAPH_DOCS_OUTPUT_LIVE_CONSUMER_DOWNSTREAM_SAFE_SUMMARY_CONSUMER_NOOP_REGISTRATION_REVIEW_SCAN_FALSE_FLAG_KEYS
  ) {
    assertDisabledOption(value[fieldName], fieldName, label);
  }
  for (const [key, entry] of Object.entries(value)) {
    if (
      GRAPH_DOCS_OUTPUT_LIVE_CONSUMER_DOWNSTREAM_SAFE_SUMMARY_CONSUMER_NOOP_REGISTRATION_REVIEW_SCAN_FALSE_FLAG_KEYS
        .includes(key)
      && entry === false
    ) {
      continue;
    }
    if (
      isSensitiveFieldName(key)
        || GRAPH_DOCS_OUTPUT_LIVE_CONSUMER_WRITER_RESULT_TO_REDACTION_AUDIT_BOUNDARY_GAP_SCAN_SENSITIVE_FIELD_KEY_SET
          .has(normalizedKey(key))
    ) {
      throw new Error(`${label} rejected sensitive runtime field: ${pathLabel}.${key}`);
    }
    if (
      GRAPH_RUNTIME_DOCS_ARTIFACT_WRITE_OBSERVABILITY_FORBIDDEN_PATH_KEYS
        .includes(key)
      || normalizedKey(key).endsWith('path')
    ) {
      throw new Error(`${label} must not expose path field: ${pathLabel}.${key}`);
    }
    if (
      GRAPH_DOCS_OUTPUT_LIVE_CONSUMER_DOWNSTREAM_SAFE_SUMMARY_CONSUMER_NOOP_REGISTRATION_REVIEW_SCAN_RUNTIME_PRODUCT_KEY_SET
        .has(normalizedKey(key))
    ) {
      throw new Error(`${label} rejected runtime field: ${pathLabel}.${key}`);
    }
    assertNoGraphDocsOutputLiveConsumerDownstreamSafeSummaryConsumerNoopRegistrationReviewScanRuntimeProducts(
      entry,
      label,
      `${pathLabel}.${key}`,
    );
  }
  return true;
}

