      GRAPH_DOCS_OUTPUT_LIVE_CONSUMER_DOWNSTREAM_SAFE_SUMMARY_CONSUMER_NOOP_DELIVERY_SERVICE_REVIEW_SCAN_FALSE_FLAG_KEYS
        .includes(key)
      && entry === false
