function assertNoGraphDocsOutputLiveConsumerDownstreamSafeSummaryConsumerNoopDeliveryContractorReviewScanRuntimeProducts(
  value = {},
  label = 'GraphDocsOutputLiveConsumerDownstreamSafeSummaryConsumerNoopDeliveryContractorReviewScan',
  pathLabel = label,
) {
  assertNoGraphDocsOutputLiveConsumerDownstreamSafeSummaryConsumerNoopDeliveryVendorReviewScanRuntimeProducts(
    value,
    label,
    pathLabel,
  );
  if (!value || typeof value !== 'object') {
    return true;
  }
  for (
    const fieldName
    of GRAPH_DOCS_OUTPUT_LIVE_CONSUMER_DOWNSTREAM_SAFE_SUMMARY_CONSUMER_NOOP_DELIVERY_CONTRACTOR_REVIEW_SCAN_FALSE_FLAG_KEYS
  ) {
    assertDisabledOption(value[fieldName], fieldName, label);
  }
  for (const [key, entry] of Object.entries(value)) {
    if (
      GRAPH_DOCS_OUTPUT_LIVE_CONSUMER_DOWNSTREAM_SAFE_SUMMARY_CONSUMER_NOOP_DELIVERY_CONTRACTOR_REVIEW_SCAN_FALSE_FLAG_KEYS
        .includes(key)
      && entry === false
    ) {
      continue;
    }
    if (
      isSensitiveFieldName(key)
        || GRAPH_DOCS_OUTPUT_LIVE_CONSUMER_DOWNSTREAM_SAFE_SUMMARY_CONSUMER_NOOP_DELIVERY_CONTRACTOR_REVIEW_SCAN_SENSITIVE_ALIAS_PATTERN
          .test(normalizedKey(key))
    ) {
      throw new Error(`${label} rejected sensitive runtime field: ${pathLabel}.${key}`);
    }
    if (
      GRAPH_DOCS_OUTPUT_LIVE_CONSUMER_DOWNSTREAM_SAFE_SUMMARY_CONSUMER_NOOP_DELIVERY_CONTRACTOR_REVIEW_SCAN_RUNTIME_PRODUCT_KEY_SET
        .has(normalizedKey(key))
    ) {
      throw new Error(`${label} rejected runtime field: ${pathLabel}.${key}`);
    }
    assertNoGraphDocsOutputLiveConsumerDownstreamSafeSummaryConsumerNoopDeliveryContractorReviewScanRuntimeProducts(
      entry,
      label,
      `${pathLabel}.${key}`,
    );
  }
  return true;
}

